import{_ as i,c as l,o,ag as a}from"./chunks/framework.piE7uVCg.js";const p=JSON.parse('{"title":"Serrure autonome VD08-ZM","description":"","frontmatter":{},"headers":[],"relativePath":"securite/access/serrure_auth.md","filePath":"securite/access/serrure_auth.md"}'),r={name:"securite/access/serrure_auth.md"};function u(t,e,s,n,d,c){return o(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="serrure-autonome-vd08-zm" tabindex="-1"><a href="./readme.html">Serrure autonome VD08-ZM</a> <a class="header-anchor" href="#serrure-autonome-vd08-zm" aria-label="Permalink to &quot;[Serrure autonome VD08-ZM](readme.md)&quot;">​</a></h1><h2 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h2><p>Serrure autonome qui fonctionne avec des piles (4xAA) et qui peut etre alimenté en 12v.</p><h2 id="creation-du-1er-code-master" tabindex="-1">Création du 1er code master <a class="header-anchor" href="#creation-du-1er-code-master" aria-label="Permalink to &quot;Création du 1er code master&quot;">​</a></h2><ol><li><code>*</code> + <code>#</code></li><li><code>1</code> puis <code>1</code> Un numero est énnoncé comme identifiant de l&#39;utilisateur</li><li>Saisir un code de 6 chiffres</li><li><code>#</code> pour valider</li><li>Saisir à nouveau un code de 6 chiffres</li><li><code>#</code> pour valider</li></ol><h2 id="creation-d-un-administrateur" tabindex="-1">Création d&#39;un administrateur <a class="header-anchor" href="#creation-d-un-administrateur" aria-label="Permalink to &quot;Création d&#39;un administrateur&quot;">​</a></h2><ol><li><code>*</code> + <code>#</code> + code admin</li><li><code>1</code> puis <code>1</code> Un numero est énnoncé comme identifiant de l&#39;utilisateur</li><li>Il faudra donc : <ol><li>Saisir un code de 6 chiffres puis <code>#</code> Saisir à nouveau un code de 6 chiffres puis <code>#</code></li><li>ou Poser une carte puis <code>#</code></li><li>ou poser un doigt pour reconnaire l&#39;empreinte puis <code>#</code></li></ol></li></ol><h2 id="ajouter-un-utilisateur" tabindex="-1">Ajouter un utilisateur <a class="header-anchor" href="#ajouter-un-utilisateur" aria-label="Permalink to &quot;Ajouter un utilisateur&quot;">​</a></h2><ol><li><code>*</code> + <code>#</code> + code admin ou empreinte admin</li><li><code>2</code> puis <code>1</code> Un numero est énnoncé comme identifiant de l&#39;utilisateur</li><li>Il faudra donc : <ol><li>Saisir un code de 6 chiffres puis <code>#</code> Saisir à nouveau un code de 6 chiffres puis <code>#</code></li><li>ou Poser une carte puis <code>#</code></li><li>ou poser un doigt pour reconnaire l&#39;empreinte puis <code>#</code></li></ol></li></ol><h2 id="supprimer-un-utilisateur" tabindex="-1">Supprimer un utilisateur <a class="header-anchor" href="#supprimer-un-utilisateur" aria-label="Permalink to &quot;Supprimer un utilisateur&quot;">​</a></h2><ol><li><code>*</code> + <code>#</code> + code admin ou empreinte admin</li><li><code>2</code> puis <code>2</code></li><li>A partir d&#39;un d&#39;ici un choix s&#39;offre à vous : <ol><li><code>1</code> pour supprimer un utilisateur, sassissez son numéro puis faites <code>#</code></li><li><code>2</code> pour supprimer tous les utilisateurs</li></ol></li></ol><h2 id="activer-l-application-mobile" tabindex="-1">Activer l&#39;application mobile <a class="header-anchor" href="#activer-l-application-mobile" aria-label="Permalink to &quot;Activer l&#39;application mobile&quot;">​</a></h2><ol><li><code>*</code> + <code>#</code> + code admin ou empreinte admin</li><li><code>4</code> puis <code>1</code></li><li>Si l&#39;appareil ennonce &quot;Succeded&quot; il faudra lancer la recherche de la serrure sur l&#39;application tuya</li></ol><h2 id="menus" tabindex="-1">Menus <a class="header-anchor" href="#menus" aria-label="Permalink to &quot;Menus&quot;">​</a></h2><ol><li>Admin setting <ol><li>add admin <ol><li>add admin</li><li>Poser une empreinte 3 fois ou saisir un code de 6 chiffres deux fois (les numéros sont générés en 0 1 2 etc)</li></ol></li><li>delete admin <ol><li>Supprimer un admin</li><li>Supprimer tous les admins</li></ol></li></ol></li><li>User serttings <ol><li>add user <ol><li>Poser une empreinte 3 fois ou saisir un code de 6 chiffres deux fois (les numéros sont générés en 10 11 12 etc)</li></ol></li><li>delete user <ol><li>Supprimer un utilisateur</li><li>Supprimer tous les utilisateurs</li></ol></li></ol></li><li>System Settings <ol><li>time settings <ol><li>année</li><li>mois</li><li>jour</li><li>heure</li><li>minutes</li></ol></li><li>language choice <ol><li>chinois</li><li>anglais</li></ol></li><li>Volume control <ol><li>low</li><li>middle</li><li>hight</li><li>mute</li></ol></li><li>Normaly open mode <ol><li>on</li><li>off</li></ol></li><li>double validation mode <ol><li>activate</li><li>cancel</li></ol></li><li>d <ol><li>on</li><li>off</li></ol></li><li>Open lock request query (code temporaire)</li></ol></li><li>Network Settings <ol><li>on</li><li>off</li></ol></li></ol><h2 id="defauts" tabindex="-1">Défauts <a class="header-anchor" href="#defauts" aria-label="Permalink to &quot;Défauts&quot;">​</a></h2><ul><li>Si le lecteur ne réagit pas avec les batteries vérifier le code des couleurs des fiches</li><li>Changer la langue si c&#39;est en chinois</li></ul><h2 id="changement-de-langue" tabindex="-1">Changement de langue <a class="header-anchor" href="#changement-de-langue" aria-label="Permalink to &quot;Changement de langue&quot;">​</a></h2><p>Pour modifier la langue des instructions vocales en anglais sur votre serrure connectée VD08-ZM, suivez ces étapes directement sur le clavier :</p><ol><li>Réveillez l’écran en touchant le clavier.</li><li>Appuyez sur <code>*</code> puis sur <code>#</code> pour accéder au menu système.</li><li>Vérifiez vos identifiants d’administrateur (appuyez sur votre empreinte digitale ou saisissez votre code d’accès administrateur suivi de <code>#</code>).</li><li>Appuyez sur <code>3</code> pour accéder aux paramètres système.</li><li>Appuyez sur <code>2</code> pour accéder au menu des paramètres de langue.</li><li>Appuyez sur <code>2</code> (ou suivez les indications vocales) pour sélectionner l’anglais, puis appuyez sur # pour confirmer.</li></ol><h2 id="reset" tabindex="-1">Reset <a class="header-anchor" href="#reset" aria-label="Permalink to &quot;Reset&quot;">​</a></h2><p>Pour reinitialiser l&#39;appareil il faut appuyer sur le bouton reset à l&#39;intérieur jusqu&#39;à ce que cela réagisse.</p>',22)])])}const h=i(r,[["render",u]]);export{p as __pageData,h as default};
